import { type MouseEvent as ReactMouseEvent } from 'react';
/**
 * @internal
 * Props for TrackAtom, representing properties related to a track.
 */
export interface TrackAtomProps {
    /** Optional label for the track. */
    label?: string;
    /** Optional callback when the mouse enters the track. */
    onMouseEnter?: (event: ReactMouseEvent) => void;
    /** Whether this track should be visible */
    hidden?: boolean;
}
